 20	import NetworkInterfaceModelSelect from './components/NetworkInterfaceModelSelect';
 21	import NetworkInterfaceNetworkSelect from './components/NetworkInterfaceNetworkSelect/NetworkInterfaceNetworkSelect';
 22	import { interfaceModelType } from './utils/constants';
 23	import { getNetworkName } from './utils/helpers';
 24	
 25	import './NetworkInterfaceModal.scss';
 26	
 27	type NetworkInterfaceModalOnSubmit = {
 28	  interfaceMACAddress: string;
 29	  interfaceModel: string;
 30	  interfaceType: string;
 31	  networkName: string;
 32	  nicName: string;
 33	};
 34	
 35	type NetworkInterfaceModalProps = {
 36	  fixedName?: boolean;
 37	  Header?: ReactNode;
 38	  headerText: string;
 39	  isEdit?: boolean;
 40	  isOpen: boolean;
 41	  namespace?: string;
 42	  nicPresentation?: NetworkPresentation;
 43	  onClose: () => void;
 44	  onSubmit: (
 45	    args: NetworkInterfaceModalOnSubmit,
 46	  ) => (
 47	    obj: V1VirtualMachine,
 48	  ) => Promise<string | V1Template | V1Template[] | V1VirtualMachine | V1VirtualMachine[] | void>;
 49	  vm: V1VirtualMachine;
 50	};
 51	
 52	const NetworkInterfaceModal: FC<NetworkInterfaceModalProps> = ({
 53	  fixedName = false,
 54	  Header = null,
 55	  headerText,
 56	  isOpen,
 57	  namespace,
 58	  nicPresentation = { iface: null, network: null },
 59	  onClose,
 60	  onSubmit,
 61	  vm,
 62	}) => {
 63	  const { t } = useKubevirtTranslation();
 64	  const { iface = null, network = null } = nicPresentation;
 65	  const [nicName, setNicName] = useState(network?.name || generatePrettyName('nic'));
 66	  const [interfaceModel, setInterfaceModel] = useState(iface?.model || interfaceModelType.VIRTIO);
 67	  const [networkName, setNetworkName] = useState(getNetworkName(network));
 68	  const [interfaceType, setInterfaceType] = useState(
 69	    interfacesTypes[getNetworkInterfaceType(iface)],
 70	  );
 71	  const [interfaceMACAddress, setInterfaceMACAddress] = useState(iface?.macAddress);
 72	  const [submitDisabled, setSubmitDisabled] = useState(true);
 73	  const [isExpanded, setIsExpanded] = useState(false);
 74	
 75	  const onSubmitModal = useCallback(() => {
 76	    return (
 77	      onSubmit &&
 78	      onSubmit({ interfaceMACAddress, interfaceModel, interfaceType, networkName, nicName })
 79	    );
 80	  }, [nicName, networkName, interfaceModel, interfaceMACAddress, interfaceType, onSubmit]);
 81	
 82	  const isHotPlugNIC =
 83	    interfaceType === interfacesTypes.bridge || interfaceType === interfacesTypes.sriov;
 84	  const vmIsRunning = isRunning(vm);
 85	  const showRestartHeader = !isHotPlugNIC;
 86	  const showRestartOrMigrateHeader = vmIsRunning && isHotPlugNIC;
 87	
 88	  return (
 89	    <TabModal<K8sResourceCommon>
 90	      headerText={headerText}
 91	      isDisabled={submitDisabled}
 92	      isOpen={isOpen}
 93	      obj={vm}
 94	      onClose={onClose}
 95	      onSubmit={onSubmitModal()}
 96	    >
 97	      <Form>
 98	        {showRestartHeader && Header}
 99	        {showRestartOrMigrateHeader && <NICHotPlugModalAlert />}
100	        <NameFormField isDisabled={fixedName} objName={nicName} setObjName={setNicName} />
101	        <NetworkInterfaceModelSelect
102	          interfaceModel={interfaceModel}
103	          setInterfaceModel={setInterfaceModel}
104	        />
105	        <NetworkInterfaceNetworkSelect
106	          isEditing={Boolean(network) && Boolean(iface)}
107	          namespace={namespace}
108	          networkName={networkName}
109	          setInterfaceType={setInterfaceType}
110	          setNetworkName={setNetworkName}
111	          setSubmitDisabled={setSubmitDisabled}
112	          vm={vm}
113	        />
114	        <ExpandableSection
115	          className="NetworkInterfaceModal__advanced"
116	          isExpanded={isExpanded}
117	          onToggle={(_, expand) => setIsExpanded(expand)}
118	          toggleText={t('Advanced')}
119	        >
120	          <NetworkInterfaceMACAddressInput
121	            interfaceMACAddress={interfaceMACAddress}
122	            isDisabled={!networkName}
123	            setInterfaceMACAddress={setInterfaceMACAddress}
124	            setIsError={setSubmitDisabled}
125	          />
126	        </ExpandableSection>
127	      </Form>
128	    </TabModal>
129	  );
130	};
131	
132	export default NetworkInterfaceModal;

